import{_ as a,o as e,c as l,ae as o}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"Vibe Coding 六周全纪录：一个人，一支AI开发队伍","description":"","frontmatter":{},"headers":[],"relativePath":"reading/vibe-coding-6weeks.md","filePath":"reading/vibe-coding-6weeks.md"}'),r={name:"reading/vibe-coding-6weeks.md"};function n(t,i,d,p,h,s){return e(),l("div",null,[...i[0]||(i[0]=[o('<h1 id="vibe-coding-六周全纪录-一个人-一支ai开发队伍" tabindex="-1">Vibe Coding 六周全纪录：一个人，一支AI开发队伍 <a class="header-anchor" href="#vibe-coding-六周全纪录-一个人-一支ai开发队伍" aria-label="Permalink to &quot;Vibe Coding 六周全纪录：一个人，一支AI开发队伍&quot;">​</a></h1><h1 id="共读笔记-vibe-coding-六周全纪录-一个人-一支ai开发队伍" tabindex="-1">共读笔记｜Vibe Coding 六周全纪录：一个人，一支AI开发队伍 <a class="header-anchor" href="#共读笔记-vibe-coding-六周全纪录-一个人-一支ai开发队伍" aria-label="Permalink to &quot;共读笔记｜Vibe Coding 六周全纪录：一个人，一支AI开发队伍&quot;">​</a></h1><p>和 AI 协作者一起拆解的过程记录。不是听书，是带着自己的问题去翻译。</p><hr><p>最近把整套 Vibe Coding 训练营完整走了一遍，从入门到结业，一共六周。 没有赶进度，没有跳章节，就跟着节奏一点点把理念、工具、工程、协作、重构、自动化全部跑通。 越往后越清晰：<strong>这不是在学编程，是在升级下一代的开发方式。</strong></p><h2 id="一、vibe-coding-到底是什么" tabindex="-1">一、Vibe Coding 到底是什么？ <a class="header-anchor" href="#一、vibe-coding-到底是什么" aria-label="Permalink to &quot;一、Vibe Coding 到底是什么？&quot;">​</a></h2><p>很多人理解成：AI 帮我写代码。 不对。</p><p>Vibe Coding 是一整套<strong>以人类意图为中心、以 AI 为执行主体、以工程规范为底线</strong>的现代开发范式。 人不再是打字员，而是需求定义者、任务拆解者、AI 指挥者、质量把关人。 你说得越清楚，AI 做得越稳；你工程底线越高，系统越不容易崩。</p><p>它不是捷径，是<strong>新一代开发的基本功</strong>。</p><h2 id="二、六周到底在练什么-我把它揉成三层" tabindex="-1">二、六周到底在练什么？我把它揉成三层 <a class="header-anchor" href="#二、六周到底在练什么-我把它揉成三层" aria-label="Permalink to &quot;二、六周到底在练什么？我把它揉成三层&quot;">​</a></h2><h3 id="第一层-基本功——让代码能跑、能存、能版本" tabindex="-1">第一层：基本功——让代码能跑、能存、能版本 <a class="header-anchor" href="#第一层-基本功——让代码能跑、能存、能版本" aria-label="Permalink to &quot;第一层：基本功——让代码能跑、能存、能版本&quot;">​</a></h3><p>第1–2周解决最朴素的问题： 环境怎么搭、命令怎么用、Python 怎么写、数据怎么存、代码怎么管理。 听起来基础，但这是所有系统的地基。 AI 写得再快，地基不稳，改两次就崩。</p><h3 id="第二层-ai-协作——给-ai-接上手脚与大脑" tabindex="-1">第二层：AI 协作——给 AI 接上手脚与大脑 <a class="header-anchor" href="#第二层-ai-协作——给-ai-接上手脚与大脑" aria-label="Permalink to &quot;第二层：AI 协作——给 AI 接上手脚与大脑&quot;">​</a></h3><p>第3周开始真正进入状态：</p><ul><li>MCP 让 AI 能读文件、查数据库、操作仓库</li><li>Skills 让 AI 拥有专业工作流，比如代码审查、测试生成</li><li>提示词工程让 AI 一次做对</li><li>上下文管理让 AI 不“失忆”</li></ul><p>这一层的质变是： <strong>AI 从聊天机器人，变成了坐在你旁边的合作者。</strong></p><h3 id="第三层-工程底线——防止系统越改越烂" tabindex="-1">第三层：工程底线——防止系统越改越烂 <a class="header-anchor" href="#第三层-工程底线——防止系统越改越烂" aria-label="Permalink to &quot;第三层：工程底线——防止系统越改越烂&quot;">​</a></h3><p>第4–5周是真正拉开差距的部分：</p><ul><li>日志：出事能追溯</li><li>测试：改代码不崩</li><li>回归测试：加功能不拆家</li><li>CI/CD：提交即检查</li><li>代码门禁：拦死烂代码</li><li>重构：让系统越写越干净</li><li>Subagent：让 AI 组成团队并行干活</li></ul><p>到这里你会突然明白： <strong>AI 写代码不难，难的是不让项目崩。</strong></p><h2 id="三、最触动我的一个点-从-写代码-到-指挥ai团队" tabindex="-1">三、最触动我的一个点：从“写代码”到“指挥AI团队” <a class="header-anchor" href="#三、最触动我的一个点-从-写代码-到-指挥ai团队" aria-label="Permalink to &quot;三、最触动我的一个点：从“写代码”到“指挥AI团队”&quot;">​</a></h2><p>前五周最冲击我的，是 Subagent 协作模式。 一个主 Agent，调度前端、后端、安全、测试、代码审查专家。 它们各司其职、互不干扰、并行工作、最后汇总。</p><p>我只需要说清楚： 做什么、约束是什么、质量底线在哪里。</p><p>那一刻真实感受到： <strong>未来一个人就是一支队伍。</strong> 你不再需要招满一个团队才能做产品。</p><h2 id="四、ai-时代的开发-到底在比什么" tabindex="-1">四、AI 时代的开发，到底在比什么？ <a class="header-anchor" href="#四、ai-时代的开发-到底在比什么" aria-label="Permalink to &quot;四、AI 时代的开发，到底在比什么？&quot;">​</a></h2><p>走完六周我有一个很明确的答案：</p><p>不比谁打字快。 不比谁背语法熟。 不比谁记得API多。</p><p>比的是：</p><ul><li>谁能把需求说清楚</li><li>谁能把任务拆干净</li><li>谁能把提示词写稳</li><li>谁能把测试写全</li><li>谁能把质量守住</li><li>谁能把 AI 指挥明白</li></ul><p>这是新一代开发者的核心竞争力。</p><h2 id="五、回到项目本身-诸葛菜到底意味着什么" tabindex="-1">五、回到项目本身：诸葛菜到底意味着什么？ <a class="header-anchor" href="#五、回到项目本身-诸葛菜到底意味着什么" aria-label="Permalink to &quot;五、回到项目本身：诸葛菜到底意味着什么？&quot;">​</a></h2><p>整个训练营围绕一个小而完整的项目： 诸葛菜——个人效能管理系统。</p><p>它不大，但五脏俱全：</p><ul><li>任务管理</li><li>四象限</li><li>日历与时间</li><li>统计与可视化</li><li>番茄钟</li><li>用户登录</li><li>日志、测试、自动化</li><li>AI 协作、重构、迭代</li></ul><p>它是一个<strong>可以写进简历、可以展示、可以迭代、可以当成作品集起点</strong>的真实项目。 不是Demo，不是玩具，是一套可长期维护的系统。</p><h2 id="六、一点点思考" tabindex="-1">六、一点点思考 <a class="header-anchor" href="#六、一点点思考" aria-label="Permalink to &quot;六、一点点思考&quot;">​</a></h2><p>很多人害怕 AI 取代自己。 但真正体验过 Vibe Coding 会明白： <strong>AI 不是取代者，是放大器。</strong> 它把你的思考、规划、判断力，放大十倍、百倍。</p><p>你负责“对”的事情。 AI 负责“快”的事情。</p><p>你负责方向与质量。 AI 负责实现与苦力。</p><p>这就是未来。</p><h2 id="七、小结" tabindex="-1">七、小结 <a class="header-anchor" href="#七、小结" aria-label="Permalink to &quot;七、小结&quot;">​</a></h2><p>六周很短，但足够完成一次代际升级。 从传统开发者，到 AI 协作开发者。 从写代码的人，到指挥 AI 团队的人。</p><p>Vibe Coding 不是一套技巧，是一种新的工作方式。 我才刚刚开始，慢慢迭代，慢慢积累。</p><p>不追求完美，先占坑，后面慢慢更新。 这本身就是设计哲学。</p>',44)])])}const g=a(r,[["render",n]]);export{c as __pageData,g as default};
